// 图片加载
export const imageOnload = async (url: string) => {
    return new Promise((resolve, reject) => {
        const img = new Image();
        img.src = url;
        img.addEventListener('load', (res) => {
            resolve(res);
        });
        img.onerror = (err) => {
            reject(err);
        };
    });
};
